#endif
#ifndef EINK_DC
#define EINK_DC 17
#endif
#ifndef EINK_RST
#define EINK_RST 16
#endif
#ifndef EINK_BUSY
#define EINK_BUSY 4
#endif
#ifndef EINK_MOSI
#define EINK_MOSI 21
#endif
#ifndef EINK_SCLK
#define EINK_SCLK 18
#endif

class Display {
public:
  Display();
  ~Display();
  void begin();
  void showStatus(uint8_t sensorCount, const SensorConfig* configs, const int* percentages, const int* rawValues, const char* wifiStatus);
  void showCalibrationScreen(const char* step = "");
  void showMessage(const char* msg);
  void deepSleep();

private:
  GxEPD2_3C<GxEPD2_213_B73, GxEPD2_213_B73::HEIGHT> m_display;
  // previous values for dirty check
  int m_prevPercentages[5];
  int m_prevRaw[5];
  char m_prevWifi[16];
  bool m_firstUpdate;
};

#endif // DISPLAY_H

#ifndef DISPLAY_H
#define DISPLAY_H

#include <GxEPD2_BW.h>
#include "../Common/Types.h"

// Default SPI pins for ESP32-S3 WeActStudio e-ink display (2.13" tri-color, used in BW mode)
#ifndef EINK_CS
#define EINK_CS 5
#endif
#ifndef EINK_DC
#define EINK_DC 17
#endif
#ifndef EINK_RST
#define EINK_RST 16
#endif
#ifndef EINK_BUSY
#define EINK_BUSY 4
#endif
#ifndef EINK_MOSI
#define EINK_MOSI 21
#endif
#ifndef EINK_SCLK
#define EINK_SCLK 18
#endif

class Display {
public:
  Display();
  ~Display();
  void begin();
  void showStatus(uint8_t sensorCount, const SensorConfig* configs, const int* percentages, const int* rawValues, const char* wifiStatus);
  void showCalibrationScreen(const char* step = "");
  void showMessage(const char* msg);
  void deepSleep();

private:
  GxEPD2_BW<GxEPD2_213_BN, GxEPD2_213_BN::HEIGHT> m_display;
  // previous values for dirty check
  int m_prevPercentages[5];
  int m_prevRaw[5];
  char m_prevWifi[16];
  bool m_firstUpdate;
};

#endif // DISPLAY_H

#include "Display.h"
#include <SPI.h>
#include <Fonts/FreeSans9pt7b.h>
#include <Fonts/FreeSans12pt7b.h>
#include <string.h>

// Constructor: initialize display with default pins
Display::Display() : m_display(GxEPD2_213_BN(EINK_CS, EINK_DC, EINK_RST, EINK_BUSY)), m_firstUpdate(true) {
  memset(m_prevPercentages, -1, sizeof(m_prevPercentages));
  memset(m_prevRaw, -1, sizeof(m_prevRaw));
  m_prevWifi[0] = '\0';
}

Display::~Display() {
}

void Display::begin() {
  SPI.begin(EINK_SCLK, -1, EINK_MOSI);
  m_display.init(115200, true);
  m_display.setRotation(1);
  m_display.fillScreen(GxEPD_WHITE);
  m_display.display(false);
  m_firstUpdate = true;
}

void Display::showStatus(uint8_t sensorCount, const SensorConfig* configs, const int* percentages, const int* rawValues, const char* wifiStatus) {
  // Check if anything changed
  bool changed = m_firstUpdate;
  if (!changed) {
    if (sensorCount > 5) sensorCount = 5;
    for (uint8_t i = 0; i < sensorCount; i++) {
      if (percentages[i] != m_prevPercentages[i] || rawValues[i] != m_prevRaw[i]) {
        changed = true;
        break;
      }
    }
    if (!changed && strcmp(wifiStatus, m_prevWifi) != 0) {
      changed = true;
    }
  }

  if (!changed) {
    // Fast partial update - show same content again? Actually we skip entirely
    return;
  }

  // Use partial update window for speed
  m_display.setPartialWindow(0, 0, m_display.width(), m_display.height());
  m_display.fillScreen(GxEPD_WHITE);
  m_display.setTextColor(GxEPD_BLACK);
  m_display.setFont(&FreeSans9pt7b);

  int16_t yStart = 10;
  int16_t yStep = 20;
  char nameBuf[9];
  char pctBuf[8];

  for (uint8_t i = 0; i < sensorCount; i++) {
    strncpy(nameBuf, configs[i].name, 8);
    nameBuf[8] = '\0';

    if (configs[i].dryRaw != configs[i].wetRaw) {
      snprintf(pctBuf, sizeof(pctBuf), "%d%%", percentages[i]);
    } else {
      snprintf(pctBuf, sizeof(pctBuf), "?");
    }

    m_display.setCursor(10, yStart + i * yStep);
    m_display.print(nameBuf);
    m_display.print("  ");
    m_display.print(pctBuf);
    m_display.print("  ");
    m_display.println(rawValues[i]);

    // Store for next comparison
    m_prevPercentages[i] = percentages[i];
    m_prevRaw[i] = rawValues[i];
  }

  m_display.setCursor(10, yStart + sensorCount * yStep + 10);
  m_display.print("WiFi: ");
  m_display.println(wifiStatus);

  strncpy(m_prevWifi, wifiStatus, sizeof(m_prevWifi)-1);
  m_prevWifi[sizeof(m_prevWifi)-1] = '\0';

  m_display.display(true); // fast partial update
  m_firstUpdate = false;
}

void Display::showCalibrationScreen(const char* step) {
  m_display.setFullWindow();
  m_display.fillScreen(GxEPD_WHITE);
  m_display.setTextColor(GxEPD_BLACK);
  m_display.setFont(&FreeSans12pt7b);

  int16_t tbx, tby; uint16_t tbw, tbh;
  m_display.getTextBounds("Calibrating...", 0, 0, &tbx, &tby, &tbw, &tbh);
  m_display.setCursor((m_display.width() - tbw) / 2, tbh + 10);
  m_display.println("Calibrating...");

  if (step && step[0]) {
    m_display.setFont(&FreeSans9pt7b);
    m_display.getTextBounds(step, 0, 0, &tbx, &tby, &tbw, &tbh);
    m_display.setCursor((m_display.width() - tbw) / 2, m_display.height() / 2);
    m_display.println(step);
  }

  m_display.display(false);
  m_firstUpdate = true;
}

void Display::showMessage(const char* msg) {
  m_display.setFullWindow();
  m_display.fillScreen(GxEPD_WHITE);
  m_display.setTextColor(GxEPD_BLACK);
  m_display.setFont(&FreeSans9pt7b);

  int16_t tbx, tby; uint16_t tbw, tbh;
  m_display.getTextBounds(msg, 0, 0, &tbx, &tby, &tbw, &tbh);
  m_display.setCursor((m_display.width() - tbw) / 2, (m_display.height() + tbh) / 2);
  m_display.println(msg);

  m_display.display(false);
  m_firstUpdate = true;
}

void Display::deepSleep() {
  m_display.powerOff();
}

