 73: bool WebServer::connectToSavedWiFi() {
 74:   String ssid = preferences.getString("ssid", "");
 75:   String pass = preferences.getString("pass", "");
 76:   if (ssid.length() == 0) return false;
 77:   
 78:   WiFi.mode(WIFI_STA);
 79:   WiFi.begin(ssid.c_str(), pass.c_str());
 80:   
 81:   unsigned long startAttempt = millis();
 82:   while (WiFi.status() != WL_CONNECTED && millis() - startAttempt < 10000) {
 83:     delay(100);
 84:   }
 85:   
 86:   return WiFi.status() == WL_CONNECTED;
 87: }
