// static method to get index from query
int WebServer::getIndexFromParam(AsyncWebServerRequest *request) {
  if (!request->hasParam("index")) {
    return -1;
  }
  String indexStr = request->getParam("index")->value();
  int index = indexStr.toInt();
  if (index < 0 || index >= MAX_SENSORS) {
    return -1;
  }
  return index;
}

void WebServer::handleUpdate(AsyncWebServerRequest *request, String filename, size_t index, uint8_t *data, size_t len, bool final) {
  if (!index) {
    if (!Update.begin(UPDATE_SIZE_UNKNOWN)) {
      m_updateInProgress = false;
      return request->send(500, "text/plain", "Update begin failed");
    }
    m_updateStartTime = millis();
    Serial.printf("OTA update started: %s\n", filename.c_str());
  }
  // Check timeout (60 seconds)
  if (millis() - m_updateStartTime > 60000) {
    Update.abort();
    m_updateInProgress = false;
    request->send(408, "text/plain", "Update timeout");
    return;
  }
  if (Update.write(data, len) != len) {
    Update.abort();
    m_updateInProgress = false;
    return request->send(500, "text/plain", "Write error");
  }
  if (final) {
    if (Update.end(true)) {
      Serial.println("OTA update success! Rebooting...");
      m_updateInProgress = false;
      request->send(200, "text/plain", "Update success. Rebooting...");
      delay(500);
      ESP.restart();
    } else {
      Serial.printf("Update error: %s\n", Update.errorString());
      m_updateInProgress = false;
      request->send(500, "text/plain", "Update failed: " + String(Update.errorString()));
    }
  }
}

