 77: bool WebServer::connectToSavedWiFi() {
 78:   String ssid = preferences.getString("ssid", "");
 79:   String pass = preferences.getString("pass", "");
 80:   if (ssid.length() == 0) return false;
 81:   
 82:   WiFi.mode(WIFI_STA);
 83:   WiFi.begin(ssid.c_str(), pass.c_str());
 84:   
 85:   unsigned long startAttempt = millis();
 86:   while (WiFi.status() != WL_CONNECTED && millis() - startAttempt < 10000) {
 87:     delay(100);
 88:     esp_task_wdt_reset();
 89:   }
 90:   
 91:   return WiFi.status() == WL_CONNECTED;
 92: }
